def _function_to_nested(function: Function) -> FunctionNested:
    """Convert flat Function to nested format."""
    attrs = FunctionAttributes()
    _populate_function_attrs(attrs, function)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        function, _FUNCTION_REL_FIELDS, FunctionRelationshipAttributes
    )
    return FunctionNested(
        guid=function.guid,
        type_name=function.type_name,
        status=function.status,
        version=function.version,
        create_time=function.create_time,
        update_time=function.update_time,
        created_by=function.created_by,
        updated_by=function.updated_by,
        classifications=function.classifications,
        classification_names=function.classification_names,
        meanings=function.meanings,
        labels=function.labels,
        business_attributes=function.business_attributes,
        custom_attributes=function.custom_attributes,
        pending_tasks=function.pending_tasks,
        proxy=function.proxy,
        is_incomplete=function.is_incomplete,
        provenance_type=function.provenance_type,
        home_id=function.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _function_from_nested(nested: FunctionNested) -> Function:
    """Convert nested format to flat Function."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else FunctionAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _FUNCTION_REL_FIELDS,
        FunctionRelationshipAttributes,
    )
    return Function(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_function_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _function_to_nested_bytes(function: Function, serde: Serde) -> bytes:
    """Convert flat Function to nested JSON bytes."""
    return serde.encode(_function_to_nested(function))


def _function_from_nested_bytes(data: bytes, serde: Serde) -> Function:
    """Convert nested JSON bytes to flat Function."""
    nested = serde.decode(data, FunctionNested)
    return _function_from_nested(nested)


